const express = require('express');
const session = require('express-session');
const dotenv = require('dotenv');
const twilio = require('twilio');

// Load environment variables from .env file
dotenv.config();

const app = express();
const PORT = process.env.PORT || 3000;

// Twilio configuration
const twilioClient = new twilio(process.env.TWILIO_ACCOUNT_SID, process.env.TWILIO_AUTH_TOKEN);
const twilioPhoneNumber = process.env.TWILIO_PHONE_NUMBER; // Your Twilio phone number

// Session configuration
app.use(session({
    secret: process.env.SESSION_SECRET || 'a_very_strong_and_random_secret_key_for_session', // IMPORTANT: Use a strong, random secret in production
    resave: false,
    saveUninitialized: false,
    cookie: {
        secure: process.env.NODE_ENV === 'production', // Use secure cookies in production (requires HTTPS)
        httpOnly: true, // Prevent client-side JS from accessing the cookie
        maxAge: 1000 * 60 * 10 // Session cookie expires after 10 minutes (adjust as needed)
    }
}));

// Middleware to parse JSON request bodies
app.use(express.json());

// --- Helper Functions ---

/**
 * Generates a random 6-digit numeric code.
 * @returns {string} The 6-digit code.
 */
function generateOtp() {
    return Math.floor(100000 + Math.random() * 900000).toString();
}

/**
 * Sends an SMS message using Twilio.
 * @param {string} to - The recipient's phone number (e.g., '+1234567890').
 * @param {string} message - The message body.
 * @returns {Promise<boolean>} True if SMS sent successfully, false otherwise.
 */
async function sendSms(to, message) {
    if (!twilioPhoneNumber) {
        console.error('TWILIO_PHONE_NUMBER is not set in environment variables.');
        return false;
    }
    try {
        await twilioClient.messages.create({
            body: message,
            to: to,
            from: twilioPhoneNumber
        });
        console.log(`SMS sent to ${to}`);
        return true;
    } catch (error) {
        console.error(`Error sending SMS to ${to}:`, error);
        return false;
    }
}

// --- Routes ---

/**
 * POST /auth/2fa/initiate
 * Initiates the 2FA process by generating an OTP and sending it via SMS.
 * Requires 'phoneNumber' in the request body.
 */
app.post('/auth/2fa/initiate', async (req, res) => {
    const { phoneNumber } = req.body;

    if (!phoneNumber) {
        return res.status(400).json({ success: false, message: 'Phone number is required.' });
    }

    // In a real application, you would typically associate this phoneNumber
    // with an authenticated user session before sending an OTP.
    // For this example, we assume the phoneNumber provided is valid for the current context.

    const otp = generateOtp();
    const otpExpiration = Date.now() + (1000 * 60 * 2); // OTP valid for 2 minutes

    // Store OTP details in the user's session
    req.session.otp = {
        code: otp,
        phoneNumber: phoneNumber, // Store for potential future validation or context
        expires: otpExpiration
    };

    const message = `Your 2FA verification code is: ${otp}. It is valid for 2 minutes.`;
    const smsSent = await sendSms(phoneNumber, message);

    if (smsSent) {
        res.status(200).json({ success: true, message: 'OTP sent successfully. Please check your phone.' });
    } else {
        // If SMS sending fails, clear the OTP from the session to prevent invalid attempts
        delete req.session.otp;
        res.status(500).json({ success: false, message: 'Failed to send OTP. Please try again.' });
    }
});

/**
 * POST /auth/2fa/verify
 * Verifies the 2FA code provided by the user against the stored OTP in the session.
 * Requires 'code' in the request body.
 */
app.post('/auth/2fa/verify', (req, res) => {
    const { code } = req.body;

    if (!code) {
        return res.status(400).json({ success: false, message: 'Verification code is required.' });
    }

    const storedOtp = req.session.otp;

    if (!storedOtp) {
        return res.status(400).json({ success: false, message: 'No OTP initiated or session expired. Please request a new code.' });
    }

    // Check if the OTP has expired
    if (Date.now() > storedOtp.expires) {
        delete req.session.otp; // Clear expired OTP from session
        return res.status(400).json({ success: false, message: 'OTP has expired. Please request a new one.' });
    }

    // Verify the provided code against the stored code
    if (code === storedOtp.code) {
        // OTP is valid. Clear it from the session to prevent reuse.
        delete req.session.otp;

        // In a real application, at this point, you would typically:
        // 1. Mark the user's session as fully authenticated (e.g., req.session.isAuthenticated = true).
        // 2. Redirect the user to a protected resource or issue an authentication token.
        res.status(200).json({ success: true, message: 'Two-factor authentication successful!' });
    } else {
        // Invalid code. You might want to implement rate limiting or lockout mechanisms here
        // after multiple failed attempts to prevent brute-force attacks.
        res.status(401).json({ success: false, message: 'Invalid verification code.' });
    }
});

// Basic root route for testing server status
app.get('/', (req, res) => {
    res.send('Welcome to the 2FA Express Application!');
});

